use std::net::{Ipv4Addr, SocketAddr};

struct ScanResult {
    address: SocketAddr,
    status_code: u16,
    details: Option<String>,
}

fn analyze_result(result: ScanResult) -> String {
    match result.details.as_ref() {
        Some(detail) if detail.contains("open") => format!("e[32mSuccess: {} is open.e[0m", result.address),
        Some(_) => format!("e[31mFailure: {}. Details: {}e[0m", result.address, result.details.as_ref().unwrap()),
        None if result.status_code == 200 => format!("e[34mInfo: {} returned 200 OK.e[0m", result.address),
        _ => format!("e[37mUnknown: {}. Status: {}e[0m", result.address, result.status_code),
    }
}

fn main() {
    let open_result = ScanResult {
        address: "192.168.1.1:80".parse().unwrap(),
        status_code: 200,
        details: Some("Connection established, port is open.".to_string()),
    };

    let closed_result = ScanResult {
        address: "192.168.1.5:443".parse().unwrap(),
        status_code: 404,
        details: Some("No active listener found.".to_string()),
    };

    let unknown_result = ScanResult {
        address: "192.168.1.99:22".parse().unwrap(),
        status_code: 503,
        details: None,
    };

    println!("{}", analyze_result(open_result));
    println!("{}", analyze_result(closed_result));
    println!("{}", analyze_result(unknown_result));
}

use std::collections::HashMap;

struct SearchResult {
    vector_id: u64,
    similarity_score: f32,
    metadata: HashMap<String, String>,
}

fn process_search_result(data: (u64, f32, HashMap<String, String>)) -> Option<(u64, f32)> {
    let (id, score, metadata) = data;
    if !metadata.is_empty() {
        Some((id, score))
    } else {
        println!("Warning: Processing result with no extra tags.");
        Some((id, score))
    }
}

fn main() {
    let mut meta1 = HashMap::new();
    meta1.insert("source".to_string(), "db_a".to_string());
    let result_tuple: (u64, f32, HashMap<String, String>) = (101, 0.95, meta1);

    if let Some((id, score)) = process_search_result(result_tuple) {
        println!("Successfully extracted ID and Score: {} and {}", id, score);
    }

    let mut meta2 = HashMap::new();
    let result_tuple_simple: (u64, f32, HashMap<String, String>) = (102, 0.88, meta2);

    if let Some((id, score)) = process_search_result(result_tuple_simple) {
        println!("Successfully extracted ID and Score: {} and {}", id, score);
    }
}

use std::collections::HashMap;

struct UserRecord {
    id: u32,
    username: String,
    is_admin: bool,
}

fn process_result(data: Result<(UserRecord, HashMap<String, i32>), String>) {
    match data {
        Ok((user, metadata)) => {
            if user.id == 42 && metadata.contains_key("session_count") {
                let count = metadata.get("session_count").unwrap_or(&0);
                println!("Found special user {} with admin status and {} sessions.", user.username, *count);
            }
        }
        Err(e) => {
            eprintln!("Error processing data: {}", e);
        }
    }
}

fn main() {
    let mut metadata = HashMap::new();
    metadata.insert("session_count".to_string(), 10);

    let special_user = UserRecord { 
        id: 42,
        username: "DataMaster".to_string(),
        is_admin: true
    };

    let ok_result = Ok((special_user, metadata));
    process_result(ok_result);

    let bad_result = Err("Network timeout".to_string());
    process_result(bad_result);
}

use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Deserialize, Serialize)]
pub struct Vector3 {
    pub x: f64,
    pub y: f64,
    pub z: f64,
}

#[derive(Debug, Deserialize, Serialize)]
pub struct Point2D {
    pub u: f64,
    pub v: f64,
}

#[derive(Debug, Deserialize, Serialize)]
pub enum DataRecord {
    Vector(Vector3),
    Coordinates(Point2D),
    Scalar(f64),
}

fn process_record(record: &DataRecord) -> Option<f64> {
    match record {
        DataRecord::Vector(v) => Some(v.x * v.y + v.z),
        DataRecord::Coordinates(p) => Some(p.u.powi(2) + p.v.powi(2)),
        DataRecord::Scalar(s) => Some(*s * 2.0),
    }
}

fn main() {
    let records_to_process = vec![
        DataRecord::Vector(Vector3 { x: 1.0, y: 2.0, z: 3.0 }),
        DataRecord::Coordinates(Point2D { u: 3.0, v: 4.0 }),
        DataRecord::Scalar(5.0),
    ];

    for record in &records_to_process {
        if let Some(result) = process_record(record) {
            println!("Processed value: {}", result);
        }
    }
}

use std::collections::HashMap;

struct Config {
    username: String,
    project_path: String,
    version: u32,
}

fn process_config(settings: Config) {
    let name = settings.username;
    let path = settings.project_path;
    let ver = settings.version;
    println!("Processing config for user: {}. Path: {}, Version: {}", name, path, ver);
}

fn main() {
    let my_settings = Config {
        username: String::from("devuser"),
        project_path: String::from("/etc/dotfiles/"),
        version: 3,
    };
    process_config(my_settings);
}
